return items.map(function(item) {
  /* ---------- 1. Campos de entrada ---------- */
  const termoOriginal = (
    item.json.TermoPesquisa ||
    item.json.termo ||
    item.json.descricao ||
    ''
  ).toString().trim();

  const termo = termoOriginal
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  /* ---------- 2. Listas de apoio ---------- */
  const stopwords = ['de','da','do','a','o','e','para','com','em','as','os','na','no','por','a','das','dos','um','uma','ao','nao','p','q','c','s'];
  const tipos = ['pincel','rolo','bandeja','extensor','espatula','desempenadeira','lixa','fita','bico','filtro','kit','massa','tinta','verniz','esmalte','spray','selador','removedor','thinner','diluente','resina','silicone'];
  const formatos = ['angular','reto','chanfrado','oval','plano','redondo'];
  const tamanhos = ['pequeno','medio','grande','mini','extra','xl'];
  const acabamentos = ['fosco','acetinado','semi-brilho','brilhante','semibrilho','semi brilho','mate','matte','metalico','texturizado','satinado','seda'];
  const cores = ['branco','preto','cinza','bege','areia','palha','gelo','neve','marfim','perola','grafite','chumbo','azul','verde','vermelho','amarelo','laranja','rosa','lilas','roxo','marrom','caramelo','chocolate','coral','terracota','ocre','pessego','camurca','creme','off-white','offwhite','off white','nude','champagne','platina'];

  /* ---------- 3. Tokeniza ---------- */
  const tokens = termo.split(/[\s,;.()\-\/]+/).filter(t => t.length > 1 && !stopwords.includes(t));

  /* ---------- 4. Classifica ---------- */
  let tipo_principal = '';
  let cor = '';
  let tamanho = '';
  let acabamento = '';
  let marca = '';
  let volume = '';
  const extras = [];

  // Detecta volume
  const volRegex = /(\d+(?:[.,]\d+)?\s*(?:l|litro|litros|ml|kg|g|galao|lata|balde))\b/gi;
  const volMatch = termo.match(volRegex);
  if (volMatch) volume = volMatch[0];

  for (const tk of tokens) {
    if (tipos.includes(tk) && !tipo_principal) { tipo_principal = tk; continue; }
    if (cores.includes(tk) && !cor) { cor = tk; continue; }
    if (tamanhos.includes(tk) && !tamanho) { tamanho = tk; continue; }
    if (acabamentos.includes(tk) && !acabamento) { acabamento = tk; continue; }
    if (formatos.includes(tk)) { extras.push(tk); continue; }
    extras.push(tk);
  }

  if (!tipo_principal && extras.length > 0) {
    tipo_principal = extras.shift();
  }

  // Query para similarity
  const queryParts = [tipo_principal, ...extras].filter(Boolean);
  const queryFull = queryParts.join(' ');

  return {
    json: {
      empresa_id: item.json.empresa_id,
      loja: item.json.loja,
      telefone: item.json.telefone,
      session_id: item.json.session_id,
      termoOriginal: termoOriginal,
      tipo_principal: queryFull || termoOriginal,
      cor: cor,
      tamanho: tamanho,
      volume: volume,
      acabamento: acabamento,
      marca: marca,
      extras: extras.join(' ')
    }
  };
});

// Junta contexto do pedido com resultados SQL
const resultadosSQL = $input.all().map(i => i.json || i);
const contextoPedido = $node['PREPARA QUERY'] ? $node['PREPARA QUERY'].json : {};

const norma = v => v === null || v === undefined ? '' : String(v).trim();

const resultados = [];
for (const produto of resultadosSQL) {
  if (!produto || !produto.codigo_produto) continue;
  const preco = Number(produto.preco || 0);
  if (preco <= 0.1) continue;
  resultados.push({
    codigo_produto: norma(produto.codigo_produto),
    descricao: produto.descricao || null,
    marca: produto.marca || null,
    preco: preco,
    score: produto.score || 0
  });
}

return [{
  json: {
    contexto: {
      termoOriginal: contextoPedido.termoOriginal || '',
      tipo_principal: contextoPedido.tipo_principal || '',
      cor: contextoPedido.cor || '',
      acabamento: contextoPedido.acabamento || '',
      volume: contextoPedido.volume || '',
      marca: contextoPedido.marca || ''
    },
    resultados: resultados,
    empresa_id: contextoPedido.empresa_id,
    loja: contextoPedido.loja,
    telefone: contextoPedido.telefone,
    session_id: contextoPedido.session_id
  }
}];

// Formata output do AI Agent
const results = [];

for (const item of items) {
  let parsed = item.json.output;

  if (typeof parsed === 'string') {
    try {
      parsed = JSON.parse(parsed);
    } catch {
      continue;
    }
  }

  if (!Array.isArray(parsed)) continue;

  for (const prod of parsed) {
    const codigo = prod.codigo || null;
    const descricao = prod.descricao || '';
    const preco = prod.preco || 0;

    if (codigo) {
      const codigoFormatado = String(codigo).padStart(5, '0');
      results.push({
        json: {
          codigo: codigoFormatado,
          info: `${descricao} - R$ ${preco}`,
          descricao: descricao,
          preco: preco,
          empresa_id: $('JUNTA CONTEXTO E RESULTADO').first().json.empresa_id,
          loja: $('JUNTA CONTEXTO E RESULTADO').first().json.loja,
          telefone: $('JUNTA CONTEXTO E RESULTADO').first().json.telefone
        }
      });
    }
  }
}

return results.length > 0 ? results : [{ json: { _empty: true } }];

